import { create } from 'zustand';
import { getActions } from './actions.js';
const DEFAULT_THEME = {
    isDark: false,
    logo: undefined,
    appName: undefined,
    bareModal: false,
    oAuthLogoVariant: undefined,
};
export const useThemeStore = create((set, get) => (Object.assign(Object.assign({}, DEFAULT_THEME), getActions(set, get))));
